/// Returns all async exec transaction metadata.
fn get_async_metadata(&self) -> Vec<crate::pool::async_pool::AsyncTxMeta<Self::Transaction>>;

/// Submit async execution results for a transaction
///
/// Updates the state of an async transaction from AwaitingExecution to Fulfilled
/// with the provided execution output and proof.
///
/// Consumer: RPC
fn submit_async_result(
    &self,
    tx_hash: B256,
    output: Bytes,
    proof: Option<Bytes>,
    executor: Address,
) -> Result<(), AsyncUpdateError>;

/// Get async transaction metadata by original hash
///
/// Returns the async transaction metadata for inspection and validation
/// before submitting results.

/// Maintenance function to cleanup blobs that are no longer needed.
fn cleanup_blobs(&self);

/// Removes expired async transactions from the pool based on time (time-based timeout).
/// This method is called by the maintenance timer to ensure time-based eviction
/// works even during network halts.
///
/// Returns the number of transactions removed.
fn remove_async_expired_by_time(&self, max_lifetime: std::time::Duration) -> usize;

/// Removes expired scheduled transactions from the pool based on time (time-based timeout).
/// This method is called by the maintenance timer to ensure time-based eviction
/// works even during network halts.
///
/// Returns the number of transactions removed.
fn remove_scheduled_expired_by_time(&self, max_lifetime: std::time::Duration) -> usize;

